module top_module(
  input CLK, // clock signal
  input EN, // enable signal
  input TE, // test enable signal
  output ENCLK // gated clock signal
);reg clk_gated;

  always @(*) begin
    if (TE) begin
      clk_gated = 1;
    end else if (EN) begin
      clk_gated = CLK;
    end else begin
      clk_gated = 0;
    end
  end

  assign ENCLK = clk_gated;

endmodule
